import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.net.URI;
import java.util.ArrayList;
import java.util.List;

@Configuration
public class ElasticsearchConfig {

    @Value("${elasticsearch.url}")
    private String elasticsearchUrl;

    @Bean
    public RestHighLevelClient restHighLevelClient() {
        List<URI> uris = new ArrayList<>();
        for (String url : elasticsearchUrl.split(",")) {
            uris.add(URI.create(url));
        }
        return new RestHighLevelClient(RestClient.builder(uris)
                .build());
    }

    @Bean
    public ElasticsearchTemplate elasticsearchTemplate() {
        return new ElasticsearchTemplate(restHighLevelClient());
    }
}

import org.elasticsearch.index.query.QueryBuilders;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

@Service
public class ProductSearchService {

    private final RestHighLevelClient restHighLevelClient;

    @Autowired
    public ProductSearchService(RestHighLevelClient restHighLevelClient) {
        this.restHighLevelClient = restHighLevelClient;
    }

    public void indexProduct(Product product) throws Exception {
        IndexRequest request = new IndexRequest("products")
                .source(jsonBuilder()
                        .startObject()
                        .field("id", product.getId())
                        .field("name", product.getName())
                        .field("description", product.getDescription())
                        .endObject());
        restHighLevelClient.index(request);
    }

    public void searchProducts(String query) throws Exception {
        SearchRequest request = new SearchRequest("products");
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.matchQuery("name", query));
        request.source(sourceBuilder);
        SearchResponse response = restHighLevelClient.search(request, RequestOptions.DEFAULT);
        // Process the search results
    }

    public void addFacet(String facetName) throws Exception {
        SearchRequest request = new SearchRequest("products");
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.matchAllQuery());
        sourceBuilder.aggregation(AggregationBuilders.terms(facetName).field(facetName));
        request.source(sourceBuilder);
        SearchResponse response = restHighLevelClient.search(request, RequestOptions.DEFAULT);
        // Process the facet results
    }
}

